const response = $.steps.exaSearch.response || {};
const data = response.data || response;
const results = data.results || [];
const userContext = $.input.dataContext || '';

let webContext = '';
const sources = [];
results.slice(0, 5).forEach((r, i) => {
  webContext += 'SOURCE ' + (i + 1) + ': ' + (r.title || 'Untitled') + '\n';
  webContext += (r.text || r.snippet || '').slice(0, 1000) + '\n\n';
  sources.push({ title: r.title || 'Source ' + (i + 1), url: r.url || '' });
});

return { webContext, userContext, sources, hasUserData: userContext.length > 0 };

const question = $.input.question;
const ctx = $.steps.compileContext.output;

let prompt = 'You are a data analysis assistant. The user wants to analyze data or answer a data-related question. Use all available context to provide a thorough analysis.\n\n';
prompt += 'QUESTION: ' + question + '\n\n';

if (ctx.hasUserData) {
  prompt += 'USER-PROVIDED DATA CONTEXT:\n' + ctx.userContext.slice(0, 4000) + '\n\n';
}

prompt += 'WEB RESEARCH CONTEXT:\n' + ctx.webContext + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Analyze the question and all available data\n';
prompt += '- Provide data-driven insights and trends\n';
prompt += '- If the user provided data, analyze patterns and anomalies\n';
prompt += '- Suggest follow-up queries for deeper analysis\n';
prompt += '- Be specific with numbers and statistics when available\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "comprehensive analysis answer (200-400 words)",\n';
prompt += '  "keyInsights": ["insight1", "insight2", "insight3"],\n';
prompt += '  "dataPoints": [{ "metric": "name", "value": "value", "context": "what it means" }],\n';
prompt += '  "trends": ["trend1", "trend2"],\n';
prompt += '  "followUpQueries": ["query1", "query2"],\n';
prompt += '  "confidence": "high|medium|low"\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, keyInsights: [], dataPoints: [], trends: [], followUpQueries: [], confidence: 'unknown' }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const sources = $.steps.compileContext.output.sources;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Data Analysis Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Confidence:*\n' + (ai.confidence || 'N/A') },
  { type: 'mrkdwn', text: '*Data Sources:*\n' + sources.length + ' web sources' }
] });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No analysis generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Analysis:*\n' + answerText } });

if (ai.keyInsights && ai.keyInsights.length > 0) {
  blocks.push({ type: 'divider' });
  let insText = '*Key Insights:*\n';
  ai.keyInsights.slice(0, 5).forEach((ins, i) => { insText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insText.slice(0, 1800) } });
}

if (ai.dataPoints && ai.dataPoints.length > 0) {
  let dpText = '*Key Data Points:*\n';
  ai.dataPoints.slice(0, 5).forEach(dp => {
    dpText += '- *' + dp.metric + ':* ' + dp.value + ' (' + (dp.context || '') + ')\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: dpText.slice(0, 1800) } });
}

if (ai.trends && ai.trends.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Trends:* ' + ai.trends.slice(0, 4).join(' | ') } });
}

if (ai.followUpQueries && ai.followUpQueries.length > 0) {
  let fuText = '*Suggested Follow-up Queries:*\n';
  ai.followUpQueries.slice(0, 3).forEach((q, i) => { fuText += '- ' + q + '\n'; });
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: fuText.slice(0, 1800) }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa Search + Claude AI' }] });

const fallbackText = 'Data Analysis: ' + question.slice(0, 50) + ' - ' + (ai.answer || '').slice(0, 80);
return { blocks, fallbackText };
